(function (global) {
    "use strict";

    const USD_TO_EUR_RATE = 0.93;
    const ESTIMATED_DEEP_SEARCH_MODEL = "gpt-5.4";
    const ESTIMATED_BATCH_PRICING = {
        model: ESTIMATED_DEEP_SEARCH_MODEL,
        serviceTier: "flex",
        inputTokensPerBatch: 6000,
        outputTokensPerCompany: 1400,
        webSearchCallsPerBatch: 1,
        practicalMultiplier: 2.2,
        batchSize: 100,
        inputUsdPerMillion: 1.25,
        outputUsdPerMillion: 7.5,
        webSearchUsdPerCall: 0.01
    };
    const DEEP_SEARCH_BATCH_SIZE = 100;
    const DEFAULT_DESIRED_COMPANY_COUNT = 25;
    const MAX_DESIRED_COMPANY_COUNT = 500;
    const MAX_DEEP_SEARCH_EXCLUDE_ITEMS = 5000;
    const AUTO_CONTINUE_DELAY_MS = 750;
    const REQUIRED_EMPTY_COMPLETION_ROUNDS = 1;
    const DEEP_SEARCH_BUSY_STYLE_ID = "softora-deep-search-busy-style";
    const TARGET_ORDER_VERSION = "distance-oisterwijk-v3";
    const PREVIOUS_TARGET_ORDER_VERSION = "distance-oisterwijk-v2";
    const REMOVED_DEFAULT_TARGET_LABELS = Object.freeze([
        "Nederland | Noord-Brabant | Oisterwijk | Haaren",
        "Nederland | Noord-Brabant | Tilburg | Tilburg"
    ]);
    const helpers = global.SoftoraDatabaseDeepSearchHelpers;
    // Generated from the supplied work order, extended with CBS 2025 woonplaatsen.
    const DEFAULT_TARGET_TEXT_BASE64 = [
        "",
        "",
        "",
        "",
        "",
        "",
        "",
        "",
        "",
        "",
        "",
        "",
        "",
        "",
        "",
        "",
        "",
        "",
        "",
        "",
        ""
    ].join("");

    function decodeBase64Utf8(value) {
        const raw = String(value || "");
        if (!raw) return "";
        if (typeof TextDecoder === "function" && typeof Uint8Array === "function" && typeof atob === "function") {
            const binary = atob(raw);
            const bytes = new Uint8Array(binary.length);
            for (let index = 0; index < binary.length; index += 1) {
                bytes[index] = binary.charCodeAt(index);
            }
            return new TextDecoder("utf-8").decode(bytes);
        }
        if (typeof Buffer === "function") {
            return Buffer.from(raw, "base64").toString("utf8");
        }
        return decodeURIComponent(escape(atob(raw)));
    }

    const DEFAULT_TARGET_TEXT = decodeBase64Utf8(DEFAULT_TARGET_TEXT_BASE64);

    function normalizeString(value) {
        return String(value || "").trim();
    }

    function normalizeKey(value) {
        return normalizeString(value)
            .toLowerCase()
            .normalize("NFD")
            .replace(/[\u0300-\u036f]/g, "")
            .replace(/[^a-z0-9]+/g, " ")
            .trim();
    }

    function escapeHtml(value) {
        return normalizeString(value)
            .replace(/&/g, "&amp;")
            .replace(/</g, "&lt;")
            .replace(/>/g, "&gt;")
            .replace(/"/g, "&quot;");
    }

    function parseTargetLines(raw) {
        const seen = new Set();
        return String(raw || "")
            .split(/\r?\n/)
            .map(function (line) {
                return normalizeString(line)
                    .replace(/^\s*(?:[-*•]+|\d+[.)]?)\s*/, "")
                    .replace(/\s+/g, " ");
            })
            .filter(function (line) {
                const key = normalizeKey(line);
                if (!key || seen.has(key)) return false;
                seen.add(key);
                return true;
            });
    }

    function getRawDefaultTargetLabels() {
        return parseTargetLines(DEFAULT_TARGET_TEXT);
    }

    function getDistanceSorter() {
        return global && global.SoftoraPremiumDatabaseDistance && typeof global.SoftoraPremiumDatabaseDistance.sortTargetLabelsByDistance === "function"
            ? global.SoftoraPremiumDatabaseDistance
            : null;
    }

    function sortTargetLabelsByDistance(labels) {
        const sorter = getDistanceSorter();
        return sorter ? sorter.sortTargetLabelsByDistance(labels) : (Array.isArray(labels) ? labels.slice() : []);
    }

    function getDefaultTargetLabels() {
        return sortTargetLabelsByDistance(getRawDefaultTargetLabels());
    }

    function getLegacyV2DefaultTargetLabels() {
        return sortTargetLabelsByDistance(getRawDefaultTargetLabels().concat(REMOVED_DEFAULT_TARGET_LABELS));
    }

    function isRemovedDefaultTargetLabel(label) {
        const key = normalizeKey(label);
        return REMOVED_DEFAULT_TARGET_LABELS.some(function (removedLabel) {
            return normalizeKey(removedLabel) === key;
        });
    }

    function getProgressDefaultLabels(parsed) {
        const version = normalizeString(parsed && parsed.targetOrderVersion);
        if (version === TARGET_ORDER_VERSION) return getDefaultTargetLabels();
        if (version === PREVIOUS_TARGET_ORDER_VERSION) return getLegacyV2DefaultTargetLabels();
        return getRawDefaultTargetLabels();
    }

    function estimateRunUsd(companyCount) {
        const count = Math.max(1, Math.min(MAX_DESIRED_COMPANY_COUNT, Number(companyCount || DEFAULT_DESIRED_COMPANY_COUNT) || DEFAULT_DESIRED_COMPANY_COUNT));
        const batchSize = Math.max(1, Number(ESTIMATED_BATCH_PRICING.batchSize) || DEEP_SEARCH_BATCH_SIZE);
        const estimatedBatches = Math.max(1, Math.ceil(count / batchSize));
        const practicalMultiplier = Math.max(1, Number(ESTIMATED_BATCH_PRICING.practicalMultiplier) || 1);
        const inputTokens = scaleEstimateAmount(estimatedBatches * ESTIMATED_BATCH_PRICING.inputTokensPerBatch, practicalMultiplier);
        const outputTokens = scaleEstimateAmount(count * ESTIMATED_BATCH_PRICING.outputTokensPerCompany, practicalMultiplier);
        const webSearchCalls = Math.max(1, scaleEstimateAmount(estimatedBatches * ESTIMATED_BATCH_PRICING.webSearchCallsPerBatch, practicalMultiplier));
        const inputUsd = (inputTokens / 1000000) * ESTIMATED_BATCH_PRICING.inputUsdPerMillion;
        const outputUsd = (outputTokens / 1000000) * ESTIMATED_BATCH_PRICING.outputUsdPerMillion;
        const webSearchUsd = webSearchCalls * ESTIMATED_BATCH_PRICING.webSearchUsdPerCall;
        return Number((inputUsd + outputUsd + webSearchUsd).toFixed(6));
    }

    function getEstimateUpperMultiplier(_companyCount) {
        return 2;
    }

    function estimateRunUpperUsd(companyCount) {
        return Number((estimateRunUsd(companyCount) * getEstimateUpperMultiplier(companyCount)).toFixed(6));
    }

    function scaleEstimateAmount(value, multiplier) {
        return Math.ceil(Number((Math.max(0, Number(value) || 0) * multiplier).toFixed(6)));
    }

    function usdToEur(value) {
        return Math.max(0, Number(value || 0) || 0) * USD_TO_EUR_RATE;
    }

    function getTargetLocationName(label) {
        const parts = normalizeString(label).split("|").map(normalizeString).filter(Boolean);
        return parts.length ? parts[parts.length - 1] : "deze locatie";
    }

    function formatCompanyCountLabel(count) {
        const amount = Math.max(0, Math.round(Number(count) || 0));
        return amount + (amount === 1 ? " bedrijf" : " bedrijven");
    }

    function buildCompletedSessionButtonLabel(summary) {
        return formatCompanyCountLabel(summary && summary.addedCount) + " toegevoegd in " + getTargetLocationName(summary && summary.targetLabel);
    }

    function formatEuro(value) {
        const amount = Math.max(0, Number(value || 0) || 0);
        const visibleAmount = amount > 0 && amount < 0.01 ? 0.01 : amount;
        return "€" + visibleAmount.toLocaleString("nl-NL", {
            minimumFractionDigits: 2,
            maximumFractionDigits: 2
        });
    }

    function formatUsdAsEuro(value) {
        return formatEuro(usdToEur(value));
    }

    function wait(ms) {
        return new Promise(function (resolve) {
            setTimeout(resolve, Math.max(0, Number(ms) || 0));
        });
    }

    function ensureBusyStyles() {
        const doc = global && global.document
            ? global.document
            : (typeof document !== "undefined" ? document : null);
        if (!doc || !doc.head || doc.getElementById(DEEP_SEARCH_BUSY_STYLE_ID)) return;
        const style = doc.createElement("style");
        style.id = DEEP_SEARCH_BUSY_STYLE_ID;
        style.textContent = [
            ".deep-search-close.is-loading, .modal-bg.is-running .deep-search-close { width: 30px; height: 30px; cursor: wait; color: var(--crimson); background: rgba(139, 34, 82, 0.06); pointer-events: none; }",
            ".deep-search-close.is-loading svg, .modal-bg.is-running .deep-search-close svg { display: none; }",
            ".deep-search-close-spinner { display: block; width: 18px; height: 18px; box-sizing: border-box; border: 2px solid rgba(139, 34, 82, 0.18); border-top-color: var(--crimson); border-radius: 50%; animation: deepSearchSpin .8s linear infinite; }",
            "#deepSearchStartButton.is-session-complete:disabled { background: rgba(65, 150, 92, 0.12); color: #3f8f5a; box-shadow: inset 0 0 0 1px rgba(63, 143, 90, 0.34); opacity: 1; cursor: not-allowed; }",
            "@keyframes deepSearchSpin { to { transform: rotate(360deg); } }"
        ].join("\n");
        doc.head.appendChild(style);
    }

    function safeParseJson(raw) {
        try {
            const parsed = JSON.parse(String(raw || "{}"));
            return parsed && typeof parsed === "object" ? parsed : {};
        } catch (error) {
            return {};
        }
    }

    function uniqueStrings(values, maxItems) {
        const seen = new Set();
        const result = [];
        (values || []).forEach(function (value) {
            const normalized = normalizeString(value);
            const key = normalizeKey(normalized);
            if (!normalized || !key || seen.has(key)) return;
            seen.add(key);
            result.push(normalized.slice(0, 180));
        });
        return result.slice(0, maxItems || 180);
    }

    function normalizeWebsiteHref(value) {
        const raw = normalizeString(value);
        if (!raw) return "";
        return /^https?:\/\//i.test(raw) ? raw : "https://" + raw.replace(/^\/+/, "");
    }

    function normalizeWebsiteDisplayValue(value) {
        const raw = normalizeString(value);
        if (!raw) return "";
        return raw.replace(/^https?:\/\/www\./i, "https://").replace(/\/$/, "");
    }

    function uniqueWebsiteValues(values, maxItems) {
        const seen = new Set();
        const result = [];
        (values || []).forEach(function (value) {
            const normalized = normalizeWebsiteDisplayValue(value && value.url || value);
            const key = normalizeKey(normalized.replace(/^https?:\/\//i, ""));
            if (!normalized || !key || seen.has(key)) return;
            seen.add(key);
            result.push(normalized.slice(0, 180));
        });
        return result.slice(0, maxItems || 200);
    }

    function normalizeDesiredCompanyCount(value) {
        const cleaned = String(value || "").replace(/[^\d]/g, "");
        const parsed = Number(cleaned);
        if (!Number.isFinite(parsed) || parsed <= 0) return DEFAULT_DESIRED_COMPANY_COUNT;
        return Math.max(1, Math.min(MAX_DESIRED_COMPANY_COUNT, Math.round(parsed)));
    }

    function collectWebsitesFromCustomers(customers) {
        return (Array.isArray(customers) ? customers : []).map(function (customer) {
            return customer && (customer.website || customer.dom || customer.url || customer.site);
        });
    }

    function createTarget(label, index) {
        return {
            id: "deep-" + normalizeKey(label).replace(/[^a-z0-9]+/g, "-").slice(0, 60) + "-" + index,
            label: normalizeString(label),
            status: index === 0 ? "active" : "pending",
            batches: 0,
            found: 0,
            added: 0,
            costUsd: 0,
            placeComplete: false,
            completionReason: "",
            completionChecks: 0,
            seen: [],
            foundWebsites: [],
            lastSources: [],
            updatedAt: ""
        };
    }

    function normalizeTarget(raw, index) {
        const label = normalizeString(raw && (raw.label || raw.name || raw.target || raw));
        if (!label) return null;
        const status = ["pending", "active", "done"].indexOf(normalizeString(raw && raw.status)) !== -1
            ? normalizeString(raw.status)
            : (index === 0 ? "active" : "pending");
        return {
            id: normalizeString(raw && raw.id) || createTarget(label, index).id,
            label: label,
            status: status,
            batches: Math.max(0, Number(raw && raw.batches) || 0),
            found: Math.max(0, Number(raw && raw.found) || 0),
            added: Math.max(0, Number(raw && raw.added) || 0),
            costUsd: Math.max(0, Number(raw && raw.costUsd) || 0),
            placeComplete: Boolean(raw && raw.placeComplete),
            completionReason: normalizeString(raw && raw.completionReason),
            completionChecks: Math.max(0, Number(raw && raw.completionChecks) || 0),
            seen: uniqueStrings(raw && raw.seen, MAX_DEEP_SEARCH_EXCLUDE_ITEMS),
            foundWebsites: uniqueWebsiteValues((raw && (raw.foundWebsites || raw.websites)) || raw && raw.lastSources, 200),
            lastSources: Array.isArray(raw && raw.lastSources) ? raw.lastSources.slice(0, 40) : [],
            updatedAt: normalizeString(raw && raw.updatedAt)
        };
    }

    function serializeTargetProgress(target, index, defaultLabels) {
        const defaultLabel = normalizeString(defaultLabels[index]);
        const defaultStatus = index === 0 ? "active" : "pending";
        const progress = { index: index };
        let changed = false;

        if (!defaultLabel || normalizeKey(defaultLabel) !== normalizeKey(target && target.label)) {
            progress.label = normalizeString(target && target.label);
            changed = true;
        }
        if (normalizeString(target && target.status) !== defaultStatus) {
            progress.status = normalizeString(target && target.status);
            changed = true;
        }
        [
            "batches",
            "found",
            "added",
            "costUsd",
            "placeComplete",
            "completionReason",
            "completionChecks",
            "updatedAt"
        ].forEach(function (key) {
            const value = target && target[key];
            const hasValue = Array.isArray(value) ? value.length : Boolean(value);
            if (!hasValue) return;
            progress[key] = value;
            changed = true;
        });
        const seen = uniqueStrings(target && target.seen, MAX_DEEP_SEARCH_EXCLUDE_ITEMS);
        if (seen.length) {
            progress.seen = seen;
            changed = true;
        }
        const foundWebsites = uniqueWebsiteValues(target && target.foundWebsites, 200);
        if (foundWebsites.length) {
            progress.foundWebsites = foundWebsites;
            changed = true;
        }
        return changed ? progress : null;
    }

    function serializeTargetProgressList(targets) {
        const defaultLabels = getDefaultTargetLabels();
        return (targets || []).map(function (target, index) {
            return serializeTargetProgress(target, index, defaultLabels);
        }).filter(Boolean);
    }

    function applyTargetProgress(targets, progressItems, progressDefaultLabels) {
        const result = targets.slice();
        const defaultLabels = Array.isArray(progressDefaultLabels) ? progressDefaultLabels : getDefaultTargetLabels();
        (Array.isArray(progressItems) ? progressItems : []).forEach(function (progress, fallbackIndex) {
            let label = normalizeString(progress && progress.label);
            let index = Number.isFinite(Number(progress && progress.index)) ? Number(progress.index) : -1;
            if (!label && index >= 0) label = normalizeString(defaultLabels[index]);
            if (label) {
                const labelIndex = result.findIndex(function (target) {
                    return normalizeKey(target.label) === normalizeKey(label);
                });
                if (labelIndex === -1 && isRemovedDefaultTargetLabel(label)) return;
                if (labelIndex !== -1) index = labelIndex;
            }
            if (index < 0) index = fallbackIndex;
            const existing = result[index] || createTarget(label, index);
            const merged = normalizeTarget({
                ...existing,
                ...progress,
                label: label || existing.label,
                id: normalizeString(progress && progress.id) || existing.id
            }, index);
            if (!merged) return;
            result[index] = merged;
        });
        return result.filter(Boolean);
    }

    function applyDefaultTargets(targets) {
        const previousByKey = new Map();
        (targets || []).forEach(function (target) {
            previousByKey.set(normalizeKey(target.label), target);
        });
        const defaults = getDefaultTargetLabels().map(function (label, index) {
            return previousByKey.get(normalizeKey(label)) || createTarget(label, index);
        });
        (targets || []).forEach(function (target) {
            if (!previousByKey.has(normalizeKey(target.label))) return;
            if (defaults.some(function (item) { return normalizeKey(item.label) === normalizeKey(target.label); })) return;
            defaults.push(target);
        });
        return defaults;
    }

    function normalizeState(raw) {
        const parsed = typeof raw === "string" ? safeParseJson(raw) : (raw || {});
        const loadedTargets = Array.isArray(parsed.targets)
            ? parsed.targets.map(normalizeTarget).filter(Boolean)
            : [];
        const progressDefaultLabels = getProgressDefaultLabels(parsed);
        const targets = applyTargetProgress(applyDefaultTargets(loadedTargets), parsed.targetProgress || parsed.progress, progressDefaultLabels);
        let activeIndex = Math.max(0, Math.min(targets.length - 1, Number(parsed.activeIndex) || 0));
        if (normalizeString(parsed.targetOrderVersion) !== TARGET_ORDER_VERSION && Number.isFinite(Number(parsed.activeIndex))) {
            const legacyActiveLabel = normalizeString(progressDefaultLabels[Math.max(0, Number(parsed.activeIndex) || 0)]);
            const migratedActiveIndex = legacyActiveLabel
                ? targets.findIndex(function (target) { return normalizeKey(target.label) === normalizeKey(legacyActiveLabel); })
                : -1;
            if (migratedActiveIndex !== -1) activeIndex = migratedActiveIndex;
        }
        const activeFromStatus = targets.findIndex(function (target) {
            return target.status === "active";
        });
        if (activeFromStatus !== -1) activeIndex = activeFromStatus;
        if (targets.length && targets.every(function (target) { return target.status !== "active"; })) {
            const nextPending = targets.findIndex(function (target) { return target.status !== "done"; });
            activeIndex = nextPending === -1 ? targets.length - 1 : nextPending;
            if (targets[activeIndex].status !== "done") targets[activeIndex].status = "active";
        }
        return {
            targets: targets,
            activeIndex: targets.length ? activeIndex : 0,
            totalCostUsd: targets.reduce(function (sum, target) {
                return sum + Math.max(0, Number(target.costUsd) || 0);
            }, 0),
            desiredCompanyCount: normalizeDesiredCompanyCount(parsed.desiredCompanyCount || parsed.desiredCount),
            completedSessionSummary: null,
            updatedAt: normalizeString(parsed.updatedAt)
        };
    }

    function readDeepSearchRows(payload) {
        return fetch("/api/premium-database/deep-search-businesses", {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify(payload || {})
        }).then(function (response) {
            return response.json().catch(function () { return {}; }).then(function (body) {
                if (!response.ok || !body.ok) throw new Error(body.error || "Bedrijvenlijst ophalen mislukt.");
                if (!Array.isArray(body.rows)) throw new Error("Geen bruikbare bedrijven ontvangen.");
                return body;
            });
        });
    }

    function readDeepSearchEstimate(companyCount) {
        const count = normalizeDesiredCompanyCount(companyCount);
        return fetch("/api/premium-database/deep-search-estimate?count=" + encodeURIComponent(String(count)), {
            method: "GET",
            headers: { "Accept": "application/json" }
        }).then(function (response) {
            return response.json().catch(function () { return {}; }).then(function (body) {
                if (!response.ok || !body.ok || !body.cost) throw new Error(body.error || "Kosteninschatting mislukt.");
                return body;
            });
        });
    }

    function createController(options) {
        ensureBusyStyles();
        const nodes = options.nodes || {};
        const getUiState = options.getUiState;
        const setUiState = options.setUiState;
        const scope = normalizeString(options.scope);
        const stateKey = normalizeString(options.stateKey);
        const importRows = options.importRows;
        const fetchDeepSearchRows = options.readDeepSearchRows || readDeepSearchRows;
        const fetchDeepSearchEstimate = options.readDeepSearchEstimate || readDeepSearchEstimate;
        const autoContinueDelayMs = options.autoContinueDelayMs === 0
            ? 0
            : Math.max(0, Number(options.autoContinueDelayMs) || AUTO_CONTINUE_DELAY_MS);
        const getCustomers = options.getCustomers || function () { return []; };
        const recordApiCost = typeof options.recordApiCost === "function"
            ? options.recordApiCost
            : function () { return Promise.resolve({ ok: true }); };
        const setStatusMessage = options.setStatusMessage || function () {};
        const toast = options.toast || function () {};
        let state = normalizeState({});
        let busy = false;
        let bound = false;
        let estimateState = {
            count: 0,
            body: null,
            pending: false,
            failed: false,
            requestId: 0
        };
        const visibleSourceTargetIds = new Set();
        const sessionFoundWebsitesByTargetId = new Map();

        function getCurrentTarget() {
            return state.targets[state.activeIndex] || null;
        }

        function getCompletedSessionSummaryForTarget(target) {
            const summary = state.completedSessionSummary;
            if (!target || !summary || normalizeString(summary.targetId) !== normalizeString(target.id)) return null;
            if (Math.max(0, Number(summary.addedCount) || 0) <= 0) return null;
            return summary;
        }

        function clearCompletedSessionSummary() {
            state.completedSessionSummary = null;
        }

        function setCompletedSessionSummary(target, addedCount) {
            if (!target) return;
            state.completedSessionSummary = {
                targetId: target.id,
                targetLabel: target.label,
                addedCount: Math.max(0, Math.round(Number(addedCount) || 0))
            };
        }

        function serializeState() {
            return JSON.stringify({
                version: 2,
                targetOrderVersion: TARGET_ORDER_VERSION,
                targetProgress: serializeTargetProgressList(state.targets),
                activeIndex: state.activeIndex,
                totalCostUsd: state.totalCostUsd,
                desiredCompanyCount: normalizeDesiredCompanyCount(state.desiredCompanyCount),
                updatedAt: new Date().toISOString()
            });
        }

        function persistState() {
            if (!setUiState || !scope || !stateKey) return Promise.resolve({ ok: true });
            return setUiState(scope, {
                patch: {
                    [stateKey]: serializeState()
                },
                source: "premium-database-deep-search",
                actor: "Premium database"
            }).catch(function (error) {
                console.error("Bedrijvenlijst opslaan mislukt:", error);
                return { ok: false, error: error };
            });
        }

        function loadState() {
            if (!getUiState || !scope || !stateKey) {
                render();
                return Promise.resolve(state);
            }
            return getUiState(scope).then(function (remoteState) {
                const values = remoteState && remoteState.values && typeof remoteState.values === "object"
                    ? remoteState.values
                    : {};
                state = normalizeState(values[stateKey]);
                render();
                return state;
            }).catch(function () {
                render();
                return state;
            });
        }

        function setBusy(nextBusy) {
            busy = Boolean(nextBusy);
            [
                nodes.deepSearchStartButton,
                nodes.deepSearchDesiredCount
            ].forEach(function (button) {
                if (button) button.disabled = busy;
            });
            if (nodes.deepSearchStartButton) {
                nodes.deepSearchStartButton.textContent = busy ? "Batch loopt..." : "Bedrijven toevoegen";
            }
            if (nodes.closeDeepSearchButton) {
                const button = nodes.closeDeepSearchButton;
                if (busy && typeof button.innerHTML === "string") {
                    if (!Object.prototype.hasOwnProperty.call(button, "__deepSearchDefaultHtml")) {
                        button.__deepSearchDefaultHtml = button.innerHTML;
                    }
                    button.innerHTML = "<span class=\"deep-search-close-spinner\" aria-hidden=\"true\"></span>";
                } else if (!busy && Object.prototype.hasOwnProperty.call(button, "__deepSearchDefaultHtml") && typeof button.innerHTML === "string") {
                    button.innerHTML = button.__deepSearchDefaultHtml;
                }
                if (button.classList) button.classList.toggle("is-loading", busy);
                nodes.closeDeepSearchButton.disabled = busy;
                if (typeof nodes.closeDeepSearchButton.setAttribute === "function") {
                    nodes.closeDeepSearchButton.setAttribute("aria-label", busy ? "Bedrijvenlijst loopt" : "Sluit bedrijvenlijst");
                    nodes.closeDeepSearchButton.setAttribute("aria-disabled", busy ? "true" : "false");
                    nodes.closeDeepSearchButton.setAttribute("aria-busy", busy ? "true" : "false");
                }
            }
            if (nodes.deepSearchModal && nodes.deepSearchModal.classList) {
                nodes.deepSearchModal.classList.toggle("is-running", busy);
            }
        }

        function getSessionFoundWebsites(targetId) {
            return uniqueWebsiteValues(sessionFoundWebsitesByTargetId.get(normalizeString(targetId)) || [], 200);
        }

        function setSessionFoundWebsites(targetId, websites) {
            const normalizedTargetId = normalizeString(targetId);
            if (!normalizedTargetId) return;
            sessionFoundWebsitesByTargetId.set(normalizedTargetId, uniqueWebsiteValues(websites, 200));
        }

        function renderSources(target) {
            if (!nodes.deepSearchSources) return;
            const targetId = normalizeString(target && target.id);
            const websites = visibleSourceTargetIds.has(targetId)
                ? getSessionFoundWebsites(targetId)
                : [];
            if (!websites.length) {
                nodes.deepSearchSources.innerHTML = "<div class=\"deep-search-empty\">Nog geen websites voor deze plek.</div>";
                return;
            }
            nodes.deepSearchSources.innerHTML = websites.map(function (website) {
                const href = normalizeWebsiteHref(website);
                return "<a href=\"" + escapeHtml(href) + "\" target=\"_blank\" rel=\"noopener\">" + escapeHtml(website) + "</a>";
            }).join("");
        }

        function getDesiredCompanyCount() {
            const inputValue = nodes.deepSearchDesiredCount && "value" in nodes.deepSearchDesiredCount
                ? nodes.deepSearchDesiredCount.value
                : state.desiredCompanyCount;
            return normalizeDesiredCompanyCount(inputValue);
        }

        function renderDesiredCompanyCountControl() {
            const previousCount = state.desiredCompanyCount;
            state.desiredCompanyCount = getDesiredCompanyCount();
            if (previousCount && previousCount !== state.desiredCompanyCount) {
                clearCompletedSessionSummary();
            }
            if (!nodes.deepSearchDesiredCount || !("value" in nodes.deepSearchDesiredCount)) return;
            const nextValue = String(state.desiredCompanyCount);
            const doc = global && global.document ? global.document : null;
            if (doc && doc.activeElement === nodes.deepSearchDesiredCount) return;
            if (String(nodes.deepSearchDesiredCount.value || "") !== nextValue) {
                nodes.deepSearchDesiredCount.value = nextValue;
            }
        }

        function resetFoundWebsitesForSession(target) {
            if (!target) return;
            target.foundWebsites = [];
            target.lastSources = [];
            setSessionFoundWebsites(target.id, []);
            target.updatedAt = new Date().toISOString();
        }

        function getEstimateCostUsdForCount(desiredCount) {
            if (estimateState.count !== desiredCount || !estimateState.body || !estimateState.body.cost) return null;
            const amount = Number(estimateState.body.cost.estimatedUsd);
            return Number.isFinite(amount) && amount >= 0 ? amount : null;
        }

        function getEstimateUpperCostUsdForCount(desiredCount) {
            if (estimateState.count !== desiredCount || !estimateState.body || !estimateState.body.cost) return null;
            const amount = Number(estimateState.body.cost.upperEstimatedUsd);
            return Number.isFinite(amount) && amount >= 0 ? amount : null;
        }

        function getEstimateModelLabel(desiredCount) {
            const body = estimateState.count === desiredCount ? (estimateState.body || {}) : {};
            const cost = body.cost || {};
            const model = normalizeString(body.model || cost.model || ESTIMATED_BATCH_PRICING.model);
            const serviceTier = normalizeString(body.serviceTier || cost.serviceTier || ESTIMATED_BATCH_PRICING.serviceTier);
            return model + (serviceTier && serviceTier !== "default" && serviceTier !== "auto" ? " " + serviceTier : "");
        }

        function formatDeepSearchEstimateLabel(desiredCount) {
            const backendEstimateUsd = getEstimateCostUsdForCount(desiredCount);
            const backendUpperEstimateUsd = getEstimateUpperCostUsdForCount(desiredCount);
            const estimateUsd = backendEstimateUsd === null ? estimateRunUsd(desiredCount) : backendEstimateUsd;
            const upperEstimateUsd = backendUpperEstimateUsd === null ? estimateRunUpperUsd(desiredCount) : backendUpperEstimateUsd;
            const estimate = formatUsdAsEuro(
                estimateUsd
            );
            const upperEstimate = formatUsdAsEuro(Math.max(estimateUsd, upperEstimateUsd));
            const rangeSuffix = upperEstimate !== estimate ? " tot " + upperEstimate : "";
            const model = getEstimateModelLabel(desiredCount);
            const modelSuffix = model ? " via " + model : "";
            return "Richtprijs voor maximaal " + desiredCount + " bedrijven: " + estimate + rangeSuffix + modelSuffix + " (dashboard kan afwijken)";
        }

        function requestDeepSearchEstimate(desiredCount) {
            if (typeof fetchDeepSearchEstimate !== "function") return;
            const count = normalizeDesiredCompanyCount(desiredCount);
            if (
                estimateState.count === count
                && (estimateState.pending || estimateState.body || estimateState.failed)
            ) {
                return;
            }
            const requestId = estimateState.requestId + 1;
            estimateState = {
                count: count,
                body: null,
                pending: true,
                failed: false,
                requestId: requestId
            };
            Promise.resolve(fetchDeepSearchEstimate(count)).then(function (body) {
                if (estimateState.requestId !== requestId) return;
                estimateState = {
                    count: count,
                    body: body,
                    pending: false,
                    failed: false,
                    requestId: requestId
                };
                render();
            }).catch(function () {
                if (estimateState.requestId !== requestId) return;
                estimateState = {
                    count: count,
                    body: null,
                    pending: false,
                    failed: true,
                    requestId: requestId
                };
            });
        }

        function render() {
            const target = getCurrentTarget();
            renderDesiredCompanyCountControl();
            const completedSummary = getCompletedSessionSummaryForTarget(target);
            const hasRunnableTarget = target && target.status !== "done";
            const canSearchTarget = hasRunnableTarget && !completedSummary;
            if (nodes.deepSearchCurrent) {
                nodes.deepSearchCurrent.textContent = hasRunnableTarget
                    ? "Nu: " + target.label
                    : "Alle plekken afgerond";
            }
            if (nodes.deepSearchCost) {
                const desiredCount = getDesiredCompanyCount();
                nodes.deepSearchCost.textContent = formatDeepSearchEstimateLabel(desiredCount);
                requestDeepSearchEstimate(desiredCount);
            }
            if (nodes.deepSearchList) {
                nodes.deepSearchList.innerHTML = state.targets.length
                    ? state.targets.map(function (item, index) {
                        const activeClass = index === state.activeIndex ? " is-active" : "";
                        const statusClass = " is-" + item.status;
                        return "<button class=\"deep-search-target" + activeClass + statusClass + "\" type=\"button\" data-deep-target-index=\"" + index + "\">"
                            + "<span>" + (index + 1) + ". " + escapeHtml(item.label) + "</span>"
                            + "</button>";
                    }).join("")
                    : "<div class=\"deep-search-empty\">Geen vaste volgorde gevonden.</div>";
            }
            renderSources(target);
            if (nodes.deepSearchStartButton) {
                const isSessionComplete = Boolean(completedSummary);
                nodes.deepSearchStartButton.disabled = busy || !canSearchTarget;
                nodes.deepSearchStartButton.textContent = busy
                    ? "Batch loopt..."
                    : (isSessionComplete ? buildCompletedSessionButtonLabel(completedSummary) : "Bedrijven toevoegen");
                if (nodes.deepSearchStartButton.classList) {
                    nodes.deepSearchStartButton.classList.toggle("is-session-complete", isSessionComplete);
                }
                if (typeof nodes.deepSearchStartButton.setAttribute === "function") {
                    nodes.deepSearchStartButton.setAttribute("aria-disabled", nodes.deepSearchStartButton.disabled ? "true" : "false");
                }
            }
        }

        function collectExistingKeys() {
            const customers = Array.isArray(getCustomers()) ? getCustomers() : [];
            const priorityKeys = [];
            const secondaryKeys = [];
            const seen = new Set();

            function addKey(list, key) {
                const normalized = normalizeString(key);
                if (!normalized || seen.has(normalized)) return;
                seen.add(normalized);
                list.push(normalized);
            }

            customers.forEach(function (customer) {
                helpers.collectCustomerMatchKeys(customer).forEach(function (key) {
                    if (key.indexOf("company-address:") === 0) {
                        addKey(secondaryKeys, key);
                    } else {
                        addKey(priorityKeys, key);
                    }
                });
            });
            return priorityKeys.concat(secondaryKeys).slice(0, MAX_DEEP_SEARCH_EXCLUDE_ITEMS);
        }

        function updateTargetAfterSearch(target, body, addedCount, addedWebsites) {
            const businesses = Array.isArray(body.businesses) ? body.businesses : [];
            const costUsd = Math.max(0, Number(body && body.cost && body.cost.estimatedUsd) || 0);
            target.batches += 1;
            target.found += Math.max(0, Number(body.found) || 0);
            target.added += Math.max(0, Number(addedCount) || 0);
            target.costUsd = Math.max(0, Number(target.costUsd) || 0) + costUsd;
            target.placeComplete = Boolean(body && body.placeComplete);
            target.completionReason = normalizeString(body && body.completionReason);
            state.totalCostUsd = Math.max(0, Number(state.totalCostUsd) || 0) + costUsd;
            target.updatedAt = new Date().toISOString();
            target.lastSources = Array.isArray(body.sources) ? body.sources.slice(0, 40) : [];
            target.foundWebsites = uniqueWebsiteValues((target.foundWebsites || []).concat(addedWebsites || []), 200);
            setSessionFoundWebsites(target.id, getSessionFoundWebsites(target.id).concat(addedWebsites || []));
            const businessKeys = [];
            businesses.forEach(function (business) {
                helpers.collectCustomerMatchKeys(business).forEach(function (key) {
                    businessKeys.push(key);
                });
            });
            target.seen = uniqueStrings(target.seen.concat(businessKeys), MAX_DEEP_SEARCH_EXCLUDE_ITEMS);
        }

        function advanceCompletedTarget(target) {
            if (!target) return false;
            target.status = "done";
            target.placeComplete = true;
            target.updatedAt = new Date().toISOString();
            const currentIndex = state.targets.indexOf(target);
            const nextIndex = state.targets.findIndex(function (item, index) {
                return index > currentIndex && item.status !== "done";
            });
            const fallbackIndex = state.targets.findIndex(function (item) {
                return item.status !== "done";
            });
            state.activeIndex = nextIndex !== -1 ? nextIndex : (fallbackIndex !== -1 ? fallbackIndex : currentIndex);
            state.targets.forEach(function (item, index) {
                if (item.status !== "done") item.status = index === state.activeIndex ? "active" : "pending";
            });
            return true;
        }

        function isTargetCompletionConfirmed(target, result) {
            const hasNewInformation = result.found > 0 || result.addedCount > 0;
            const emptyCompletion = result.completed && !hasNewInformation;
            target.completionChecks = emptyCompletion ? Math.max(0, Number(target.completionChecks) || 0) + 1 : 0;
            target.placeComplete = emptyCompletion && target.completionChecks >= REQUIRED_EMPTY_COMPLETION_ROUNDS;
            return target.placeComplete;
        }

        function runTargetBatch(target, requestedCount) {
            const beforeCustomers = Array.isArray(getCustomers()) ? getCustomers().slice() : [];
            const beforeCount = beforeCustomers.length;
            const requestCount = Math.max(1, Math.min(DEEP_SEARCH_BATCH_SIZE, normalizeDesiredCompanyCount(requestedCount || DEEP_SEARCH_BATCH_SIZE)));
            return fetchDeepSearchRows({
                target: target.label,
                count: requestCount,
                batchNumber: target.batches + 1,
                exclude: uniqueStrings(target.seen.concat(collectExistingKeys()), MAX_DEEP_SEARCH_EXCLUDE_ITEMS)
            }).then(function (body) {
                const rows = Array.isArray(body.rows) ? body.rows : [];
                target.lastSources = Array.isArray(body.sources) ? body.sources.slice(0, 40) : [];
                target.updatedAt = new Date().toISOString();
                const importPromise = rows.length > 1 ? Promise.resolve(importRows(rows)) : Promise.resolve(false);
                return importPromise.then(function (importResult) {
                    const afterCustomers = Array.isArray(getCustomers()) ? getCustomers() : [];
                    const afterCount = afterCustomers.length;
                    const importDetails = importResult && typeof importResult === "object" ? importResult : null;
                    const addedCount = importDetails
                        ? Math.max(0, Number(importDetails.addedCount) || 0)
                        : Math.max(0, afterCount - beforeCount);
                    const addedCustomers = importDetails && Array.isArray(importDetails.addedCustomers)
                        ? importDetails.addedCustomers.slice(0, addedCount || importDetails.addedCustomers.length)
                        : helpers.collectNewCustomersAfterImport(beforeCustomers, afterCustomers, addedCount);
                    const addedWebsites = importResult === false
                        ? []
                        : collectWebsitesFromCustomers(addedCustomers);
                    updateTargetAfterSearch(target, body, addedCount, addedWebsites);
                    const completed = Boolean(body && body.placeComplete);
                    const customerPersisted = !(rows.length > 1 && addedCount > 0 && importResult === false);
                    const duplicateOnlyBatch = rows.length > 1 && Math.max(0, Number(body.found) || 0) > 0 && addedCount === 0;
                    const result = {
                        addedCount: addedCount,
                        completed: completed,
                        customerPersisted: customerPersisted,
                        duplicateOnlyBatch: duplicateOnlyBatch,
                        costUsd: Math.max(0, Number(body && body.cost && body.cost.estimatedUsd) || 0),
                        found: Math.max(0, Number(body.found) || 0)
                    };
                    const costLogPromise = recordApiCost({
                        source: "premium-database-deep-search",
                        label: target.label,
                        amountUsd: result.costUsd,
                        model: body && body.cost && body.cost.model,
                        meta: {
                            target: target.label,
                            batchNumber: target.batches,
                            model: body && body.model,
                            reasoningEffort: body && body.reasoningEffort,
                            serviceTier: body && (body.serviceTier || body.cost && body.cost.serviceTier),
                            promptVersion: body && body.promptVersion,
                            found: result.found,
                            added: result.addedCount,
                            inputTokens: body && body.cost && body.cost.inputTokens,
                            outputTokens: body && body.cost && body.cost.outputTokens,
                            reasoningTokens: body && body.cost && body.cost.reasoningTokens,
                            cachedInputTokens: body && body.cost && body.cost.cachedInputTokens,
                            webSearchCalls: body && body.cost && body.cost.webSearchCalls
                        }
                    }).catch(function (error) {
                        console.error("API-kosten opslaan mislukt:", error);
                        return { ok: false, error: error };
                    });
                    return Promise.all([persistState(), costLogPromise]).then(function (results) {
                        const persistResult = results[0];
                        return {
                            ...result,
                            persisted: Boolean(persistResult && persistResult.ok !== false)
                        };
                    });
                });
            });
        }

        function runTargetUntilComplete(target, session) {
            const startedLabel = target.label;
            let targetSessionAddedCount = 0;
            const runSession = session || {
                desiredCount: getDesiredCompanyCount(),
                addedCount: 0
            };
            function nextBatch() {
                const remainingCount = Math.max(0, Number(runSession.desiredCount) - Number(runSession.addedCount || 0));
                if (remainingCount <= 0) {
                    return persistState().then(function () {
                        setStatusMessage("Gewenste aantal nieuwe bedrijven is gehaald.", "success", true);
                        return { desiredReached: true };
                    });
                }
                setStatusMessage("");
                return runTargetBatch(target, remainingCount).then(function (result) {
                    runSession.addedCount = Number(runSession.addedCount || 0) + Math.max(0, Number(result.addedCount) || 0);
                    targetSessionAddedCount += Math.max(0, Number(result.addedCount) || 0);
                    render();
                    if (result.addedCount) toast("+" + result.addedCount + " bedrijven");
                    const storageNote = result.persisted ? "" : " Let op: voortgang opslaan lukte niet.";
                    const progressMessage = runSession.addedCount + " van " + runSession.desiredCount + " gewenste bedrijven toegevoegd. ";
                    const baseMessage = "AI leverde " + result.found + " bruikbare bedrijven voor " + startedLabel + ". " + result.addedCount + " echt nieuw toegevoegd aan de database. " + progressMessage + "API-kosten: " + formatUsdAsEuro(result.costUsd) + "." + storageNote;
                    if (result.customerPersisted === false) {
                        setStatusMessage(baseMessage + " Opslaan in Supabase lukte niet, dus deze batch is gestopt zodat er niets stilletjes verloren gaat.", "error", true);
                        return { stopped: true };
                    }
                    if (result.duplicateOnlyBatch) {
                        setStatusMessage(baseMessage + " De batch is gestopt omdat er geen enkel nieuw bedrijf is toegevoegd. Zo voorkomen we dat dezelfde bestaande bedrijven API-kosten blijven maken.", "info", true);
                        return { stopped: true };
                    }
                    if (runSession.addedCount >= runSession.desiredCount) {
                        setCompletedSessionSummary(target, targetSessionAddedCount);
                        return persistState().then(function () {
                            setStatusMessage(baseMessage + " Gewenste aantal gehaald.", "success", true);
                            return { desiredReached: true };
                        });
                    }
                    if (isTargetCompletionConfirmed(target, result)) {
                        advanceCompletedTarget(target);
                        render();
                        return persistState().then(function () {
                            const nextTarget = getCurrentTarget();
                            const nextMessage = nextTarget && nextTarget !== target && nextTarget.status !== "done"
                                ? " Volgende locatie: " + nextTarget.label + "."
                                : "";
                            setStatusMessage(baseMessage + " Deze plaats is automatisch afgerond." + nextMessage, "success", true);
                            toast("Plek afgerond");
                            return { completedTarget: true };
                        });
                    }
                    return persistState().then(function () {
                        setStatusMessage("");
                        return wait(autoContinueDelayMs).then(nextBatch);
                    });
                });
            }
            return nextBatch();
        }

        function runUntilDesiredCompanyCount(session) {
            const target = getCurrentTarget();
            if (!target || target.status === "done") {
                return persistState().then(function () {
                    setStatusMessage(
                        session.addedCount > 0
                            ? "Alle plekken zijn afgerond voordat het gewenste aantal gehaald werd."
                            : "Alle plekken zijn al afgerond.",
                        session.addedCount > 0 ? "info" : "success",
                        true
                    );
                    return { finished: true };
                });
            }
            visibleSourceTargetIds.add(target.id);
            resetFoundWebsitesForSession(target);
            target.status = "active";
            render();
            void persistState();
            return runTargetUntilComplete(target, session).then(function (result) {
                if (result && (result.desiredReached || result.stopped)) return result;
                if (result && result.completedTarget) {
                    const nextTarget = getCurrentTarget();
                    if (nextTarget && nextTarget.status !== "done" && session.addedCount < session.desiredCount) {
                        return wait(autoContinueDelayMs).then(function () {
                            return runUntilDesiredCompanyCount(session);
                        });
                    }
                }
                return result;
            });
        }

        function runCurrentSearch() {
            if (busy) return Promise.resolve(false);
            const target = getCurrentTarget();
            if (!target) {
                setStatusMessage("Geen vaste locatie gevonden.", "error");
                return Promise.resolve(false);
            }
            if (target.status === "done") {
                setStatusMessage("Alle plekken zijn al afgerond.", "info", true);
                return Promise.resolve(false);
            }
            const requestedCount = getDesiredCompanyCount();
            if (state.desiredCompanyCount !== requestedCount) {
                clearCompletedSessionSummary();
            }
            state.desiredCompanyCount = requestedCount;
            if (getCompletedSessionSummaryForTarget(target)) {
                return Promise.resolve(false);
            }
            clearCompletedSessionSummary();
            const session = {
                desiredCount: state.desiredCompanyCount,
                addedCount: 0
            };
            setBusy(true);
            render();
            void persistState();
            return runUntilDesiredCompanyCount(session).then(function (result) {
                return Boolean(result && (result.desiredReached || result.completedTarget || result.finished));
            }).catch(function (error) {
                console.error("Bedrijvenlijst mislukt:", error);
                setStatusMessage("Bedrijvenlijst mislukt: " + String(error.message || "controleer de instellingen"), "error");
                return false;
            }).finally(function () {
                setBusy(false);
                render();
            });
        }

        function setActiveIndex(index) {
            if (busy) {
                setStatusMessage("Deze locatie loopt al. Wacht tot de AI hem automatisch afrondt.", "info");
                return;
            }
            clearCompletedSessionSummary();
            const targetIndex = Math.max(0, Math.min(state.targets.length - 1, Number(index) || 0));
            state.activeIndex = targetIndex;
            state.targets.forEach(function (target, itemIndex) {
                if (target.status !== "done") target.status = itemIndex === targetIndex ? "active" : "pending";
            });
            render();
            void persistState();
        }

        function open() {
            if (!nodes.deepSearchModal) return;
            visibleSourceTargetIds.clear();
            sessionFoundWebsitesByTargetId.clear();
            nodes.deepSearchModal.classList.add("on");
            nodes.deepSearchModal.setAttribute("aria-hidden", "false");
            void loadState();
        }

        function close() {
            if (!nodes.deepSearchModal) return;
            if (busy) {
                return false;
            }
            nodes.deepSearchModal.classList.remove("on");
            nodes.deepSearchModal.setAttribute("aria-hidden", "true");
            return true;
        }

        function isOpen() {
            return Boolean(nodes.deepSearchModal && nodes.deepSearchModal.classList && nodes.deepSearchModal.classList.contains("on"));
        }

        function isBusy() {
            return busy;
        }

        function bind() {
            if (bound) return;
            bound = true;
            if (nodes.deepSearchStartButton) {
                nodes.deepSearchStartButton.addEventListener("click", function () {
                    void runCurrentSearch();
                });
            }
            if (nodes.deepSearchDesiredCount) {
                nodes.deepSearchDesiredCount.addEventListener("input", function () {
                    const nextCount = getDesiredCompanyCount();
                    if (state.desiredCompanyCount !== nextCount) clearCompletedSessionSummary();
                    state.desiredCompanyCount = nextCount;
                    render();
                    void persistState();
                });
                nodes.deepSearchDesiredCount.addEventListener("blur", function () {
                    const nextCount = getDesiredCompanyCount();
                    if (state.desiredCompanyCount !== nextCount) clearCompletedSessionSummary();
                    state.desiredCompanyCount = nextCount;
                    render();
                    void persistState();
                });
            }
            if (nodes.closeDeepSearchButton) nodes.closeDeepSearchButton.addEventListener("click", close);
            if (nodes.deepSearchModal) {
                nodes.deepSearchModal.addEventListener("click", function (event) {
                    if (event.target === nodes.deepSearchModal) close();
                });
            }
            if (nodes.deepSearchList) {
                nodes.deepSearchList.addEventListener("click", function (event) {
                    const button = event.target.closest("[data-deep-target-index]");
                    if (!button) return;
                    setActiveIndex(button.getAttribute("data-deep-target-index"));
                });
            }
        }

        return {
            bind: bind,
            close: close,
            isBusy: isBusy,
            isOpen: isOpen,
            open: open,
            getDefaultTargetLabels: getDefaultTargetLabels,
            getRawDefaultTargetLabels: getRawDefaultTargetLabels,
            parseTargetLines: parseTargetLines,
            readDeepSearchEstimate: readDeepSearchEstimate,
            readDeepSearchRows: readDeepSearchRows,
            runCurrentSearch: runCurrentSearch
        };
    }

    global.SoftoraDatabaseDeepSearch = {
        createController: createController,
        getDefaultTargetLabels: getDefaultTargetLabels,
        getRawDefaultTargetLabels: getRawDefaultTargetLabels,
        parseTargetLines: parseTargetLines,
        readDeepSearchEstimate: readDeepSearchEstimate,
        readDeepSearchRows: readDeepSearchRows
    };
})(window);
